53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
65	
66	const COMPONENT_BLOCK_PREMIUM = 60;
67	
68	const sumBasePremiums = (items: Item[]): number =>
69	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
70	
71	const COMPONENT_TYPES = ["rune", "moonstone"];
72	
73	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
74	
75	const componentGroupTotal = (group: Item[]): number =>
76	  group.length === 3 ? COMPONENT_BLOCK_PREMIUM : sumBasePremiums(group);
77	
78	const itemsBaseTotal = (items: Item[]): number => {
79	  const nonComponentsTotal = sumBasePremiums(items.filter((i) => !isComponent(i)));
80	  const componentsTotal = COMPONENT_TYPES.reduce(
81	    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
82	    0,
83	  );
84	  return nonComponentsTotal + componentsTotal;
85	};
86	
87	const CURSE_SURCHARGE_RATE = 0.5;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	
91	const ITEM_SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
92	  (item) => (item.cursed ? CURSE_SURCHARGE_RATE : 0),
93	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0),
94	];
95	
96	const itemSurchargeRate = (item: Item): number =>
97	  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
98	
99	const itemSurcharges = (items: Item[]): number =>
100	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);
101	
102	const quote = ({ items }: QuoteStep): QuoteResult => ({
103	  premium: itemsBaseTotal(items) + itemSurcharges(items) + PROCESSING_FEE,
104	});
105	
106	export const runScenario = (scenario: Scenario): ScenarioResult => ({
107	  results: scenario.steps.map((step) =>
108	    step.op === "quote" ? quote(step) : { payout: 0, remainingCap: 0 },
109	  ),
110	});
