const itemsBaseTotal = (items: Item[]): number => {
  const nonComponents = items.filter((i) => !isComponent(i));
  const componentGroupsTotal = COMPONENT_TYPES.reduce(
    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
    0,
  );
  return sumBasePremiums(nonComponents) + componentGroupsTotal;
};
